## Task 20: Mouse support — sidebar resize + scroll

Read `rust/crates/app/src/router.rs` to understand existing mouse handling.

Add these mouse event handlers to `router.rs` handle() function. These should be added to the main match block:

```rust
AppEvent::Mouse { kind: crossterm::event::MouseEventKind::Moved, col, .. } => {
    state.hover_left_border = state.layout.left_visible
        && col == state.last_left_border_col;
    state.hover_right_border = state.layout.right_visible
        && col == state.last_right_border_col;
}
AppEvent::Mouse {
    kind: crossterm::event::MouseEventKind::Down(crossterm::event::MouseButton::Left),
    col,
    ..
} => {
    if state.layout.left_visible && col == state.last_left_border_col {
        state.layout.drag = Some(crate::state::DragState {
            target: crate::state::DragTarget::LeftBorder,
            start_x: col,
            start_width_pct: state.layout.left_width_pct,
        });
    } else if state.layout.right_visible && col == state.last_right_border_col {
        state.layout.drag = Some(crate::state::DragState {
            target: crate::state::DragTarget::RightBorder,
            start_x: col,
            start_width_pct: state.layout.right_width_pct,
        });
    }
}
AppEvent::Mouse {
    kind: crossterm::event::MouseEventKind::Drag(crossterm::event::MouseButton::Left),
    col,
    ..
} => {
    if let Some(drag) = state.layout.drag.clone() {
        let delta = col as i32 - drag.start_x as i32;
        let total = state.layout.terminal_cols as f32;
        match drag.target {
            crate::state::DragTarget::LeftBorder => {
                let new_pct = drag.start_width_pct + (delta as f32 / total);
                state.layout.left_width_pct = new_pct.clamp(0.05, 0.40);
            }
            crate::state::DragTarget::RightBorder => {
                let new_pct = drag.start_width_pct - (delta as f32 / total);
                state.layout.right_width_pct = new_pct.clamp(0.05, 0.40);
            }
        }
    }
}
AppEvent::Mouse {
    kind: crossterm::event::MouseEventKind::Up(_),
    ..
} => {
    state.layout.drag = None;
}
AppEvent::Mouse {
    kind: crossterm::event::MouseEventKind::ScrollUp,
    ..
} => {
    if let Some(tab) = state.active_tab_mut() {
        match &mut tab.kind {
            crate::state::TabKind::Chat { .. } => {
                tab.chat_scroll = tab.chat_scroll.saturating_sub(3);
            }
            crate::state::TabKind::FileViewer { scroll, .. } => {
                *scroll = scroll.saturating_sub(3);
            }
            crate::state::TabKind::DiffViewer { scroll, .. } => {
                *scroll = scroll.saturating_sub(3);
            }
        }
    }
}
AppEvent::Mouse {
    kind: crossterm::event::MouseEventKind::ScrollDown,
    ..
} => {
    if let Some(tab) = state.active_tab_mut() {
        match &mut tab.kind {
            crate::state::TabKind::Chat { .. } => {
                tab.chat_scroll += 3;
            }
            crate::state::TabKind::FileViewer { scroll, .. } => {
                *scroll += 3;
            }
            crate::state::TabKind::DiffViewer { scroll, .. } => {
                *scroll += 3;
            }
        }
    }
}
```

