use std::io::BufRead;
use crate::state::SessionEntry;

pub fn load_claude_sessions(paths: &clui_config::Paths) -> Vec<SessionEntry> {
    let projects_dir = &paths.claude_projects_dir;
    let Ok(proj_entries) = std::fs::read_dir(projects_dir) else {
        return Vec::new();
    };

    let mut sessions = Vec::new();
    for proj in proj_entries.filter_map(|e| e.ok()) {
        let Ok(proj_files) = std::fs::read_dir(proj.path()) else {
            continue;
        };
        for jsonl_file in proj_files
            .filter_map(|e| e.ok())
            .filter(|e| e.path().extension().and_then(|s| s.to_str()) == Some("jsonl"))
        {
            let Ok(file) = std::fs::File::open(jsonl_file.path()) else {
                continue;
            };
            let reader = std::io::BufReader::new(file);
            let mut first_user_msg: Option<String> = None;
            for line in reader.lines().filter_map(|l| l.ok()) {
                if let Ok(val) = serde_json::from_str::<serde_json::Value>(&line) {
                    if val["type"] == "user" {
                        let text = val["message"]["content"]
                            .as_str()
                            .map(|s| s.to_string())
                            .or_else(|| {
                                val["message"]["content"][0]["text"]
                                    .as_str()
                                    .map(|s| s.to_string())
                            });
                        if let Some(t) = text {
                            first_user_msg = Some(t);
                            break;
                        }
                    }
                }
            }
            if let Some(title) = first_user_msg {
                let path_str = jsonl_file.path().to_string_lossy().to_string();
                let modified = jsonl_file
                    .metadata()
                    .ok()
                    .and_then(|m| m.modified().ok())
                    .map(|t| {
                        let secs = t.duration_since(std::time::UNIX_EPOCH)
                            .unwrap_or_default().as_secs();
                        format!("{}", secs)
                    })
                    .unwrap_or_default();
                sessions.push(SessionEntry { title, path: path_str, modified });
            }
        }
    }
    sessions.sort_by(|a, b| b.modified.cmp(&a.modified));
    sessions
}
```

