27	async fn main() -> Result<()> {
28	    let cwd = std::env::current_dir()?;
29	
30	    enable_raw_mode()?;
31	    let mut stdout = io::stdout();
32	    execute!(stdout, EnterAlternateScreen, EnableMouseCapture)?;
33	    let backend = CrosstermBackend::new(io::stdout());
34	    let mut terminal = Terminal::new(backend)?;
35	    terminal.clear()?;
