38	    let mut app = AppState::new(cwd);
39	    app.layout.terminal_cols = size.width;
40	    app.layout.terminal_rows = size.height;
41	
42	    // Load initial file tree
43	    let initial_nodes = filetree::load_children(&app.cwd, 0);
44	    app.files.nodes = initial_nodes;
45	
46	    // Load skills
47	    let paths = clui_config::Paths::new();
48	    let skill_set = clui_skills::discover(&app.cwd, &paths);
49	    app.skills.repo = skill_set.repo.iter().map(|s| state::SkillEntry { name: s.name.clone(), path: s.path.clone(), overridden: s.overridden }).collect();
50	    app.skills.user = skill_set.user.iter().map(|s| state::SkillEntry { name: s.name.clone(), path: s.path.clone(), overridden: s.overridden }).collect();
51	    app.skills.global = skill_set.global.iter().map(|s| state::SkillEntry { name: s.name.clone(), path: s.path.clone(), overridden: s.overridden }).collect();
52	
53	    let result = run_loop(&mut terminal, &mut app).await;
54	
