62	async fn run_loop(
63	    terminal: &mut Terminal<CrosstermBackend<io::Stdout>>,
64	    state: &mut AppState,
65	) -> Result<()> {
66	    let settings = clui_config::Settings::from_env();
67	    let (event_tx, mut event_rx) = mpsc::channel::<AppEvent>(256);
68	
69	    // Spawn agent for initial tab if API key available
70	    if let Some(api_key) = &settings.anthropic_api_key {
71	        let config = clui_agent::AgentConfig {
72	            api_key: api_key.clone(),
73	            model: settings.default_model.clone(),
74	            max_tokens: 8192,
75	            cwd: state.cwd.to_string_lossy().to_string(),
76	        };
77	        let tx = agent_task::spawn_agent(state.tabs[0].id.clone(), config, event_tx.clone());
78	        if let TabKind::Chat { agent_tx } = &mut state.tabs[0].kind {
79	            *agent_tx = Some(tx);
80	        }
81	    }
82	
83	    // Initial git refresh
84	    let _ = event_tx.send(AppEvent::GitRefresh).await;
85	
86	    // Spawn git watcher
87	    let etx_git = event_tx.clone();
88	    tokio::spawn(async move {
89	        loop {
90	            tokio::time::sleep(Duration::from_secs(5)).await;
91	            let _ = etx_git.send(AppEvent::GitRefresh).await;
92	        }
93	    });
94	
95	    loop {
96	        terminal.draw(|f| ui::render(f, state))?;
97	
98	        // Drain async events
99	        while let Ok(evt) = event_rx.try_recv() {
