103	        if crossterm_poll(Duration::from_millis(16))? {
104	            match crossterm_read()? {
105	                Event::Key(k) => router::handle(
106	                    state,
107	                    AppEvent::Key {
108	                        code: k.code,
109	                        modifiers: k.modifiers,
110	                    },
111	                ),
112	                Event::Mouse(m) => router::handle(
113	                    state,
114	                    AppEvent::Mouse {
115	                        kind: m.kind,
116	                        col: m.column,
117	                        row: m.row,
118	                        modifiers: m.modifiers,
119	                    },
120	                ),
