use ratatui::{
    layout::Rect,
    style::{Color, Style},
    text::{Line, Span},
    widgets::{Block, BorderType, Borders, Clear, Paragraph},
    Frame,
};
use crate::state::{NotificationEntry, NotificationKind};

pub fn render_notifications(f: &mut Frame, notifications: &[NotificationEntry], area: Rect) {
    let visible: Vec<&NotificationEntry> = notifications
        .iter()
        .filter(|n| !n.is_expired())
        .take(5)
        .collect();

    let popup_width = 40u16;
    let mut y_offset = 1u16;

    for notif in visible.iter().rev() {
        let color = match notif.kind {
            NotificationKind::Success => Color::Green,
            NotificationKind::Info => Color::Cyan,
            NotificationKind::Warning => Color::Yellow,
            NotificationKind::Error => Color::Red,
        };
        let x = area.width.saturating_sub(popup_width + 2);
        let popup_area = Rect::new(x, y_offset, popup_width, 3);
        if popup_area.bottom() > area.height {
            break;
        }

        let block = Block::default()
            .borders(Borders::ALL)
            .border_type(BorderType::Rounded)
            .border_style(Style::default().fg(color));
        let para = Paragraph::new(Line::from(Span::styled(
            format!(" {} ", notif.message),
            Style::default().fg(color),
        )))
        .block(block);

        f.render_widget(Clear, popup_area);
        f.render_widget(para, popup_area);
        y_offset += 4;
    }
}

use ratatui::{
    layout::Rect,
    style::{Color, Modifier, Style},
    text::{Line, Span},
    widgets::{Block, BorderType, Borders, Clear, Paragraph},
    Frame,
};
use crate::state::ConfirmDialog;

pub fn render_confirm(f: &mut Frame, dialog: &ConfirmDialog, area: Rect) {
    let width = 50u16;
    let height = 7u16;
    let x = area.width.saturating_sub(width) / 2;
    let y = area.height.saturating_sub(height) / 2;
    let popup_area = Rect::new(x, y, width, height);

    let block = Block::default()
        .borders(Borders::ALL)
        .border_type(BorderType::Rounded)
        .border_style(Style::default().fg(Color::Red))
        .title(Span::styled(
            " Confirm ",
            Style::default()
                .fg(Color::Red)
                .add_modifier(Modifier::BOLD),
        ));

    let inner = block.inner(popup_area);
    f.render_widget(Clear, popup_area);
    f.render_widget(block, popup_area);

    let lines = vec![
        Line::default(),
        Line::from(Span::styled(
            format!("  {}", dialog.message),
            Style::default().fg(Color::White),
        )),
        Line::default(),
        Line::from(vec![
            Span::raw("  "),
            Span::styled(
                " [Y]es ",
                Style::default().fg(Color::Black).bg(Color::Red),
            ),
            Span::raw("  "),
            Span::styled(
                " [N]o ",
                Style::default().fg(Color::Black).bg(Color::DarkGray),
            ),
        ]),
    ];
    let para = Paragraph::new(lines);
    f.render_widget(para, inner);
}

