    if state.layout.left_visible && col == state.last_left_border_col {
        state.layout.drag = Some(crate::state::DragState {
            target: crate::state::DragTarget::LeftBorder,
            start_x: col,
            start_width_pct: state.layout.left_width_pct,
        });
    } else if state.layout.right_visible && col == state.last_right_border_col {
        state.layout.drag = Some(crate::state::DragState {
            target: crate::state::DragTarget::RightBorder,
            start_x: col,
            start_width_pct: state.layout.right_width_pct,
