use ratatui::{
    layout::Rect,
    style::{Color, Modifier, Style},
    text::{Line, Span},
    widgets::{Block, BorderType, Borders, Paragraph},
    Frame,
};
use crate::state::AppState;

pub fn render_sessions(f: &mut Frame, state: &AppState, area: Rect) {
    let block = Block::default()
        .borders(Borders::ALL)
        .border_type(BorderType::Rounded)
        .border_style(Style::default().fg(Color::DarkGray));
    let inner = block.inner(area);
    f.render_widget(block, area);

    let mut lines: Vec<Line> = Vec::new();

    // Active tabs (always shown at top)
    for (i, tab) in state.tabs.iter().enumerate() {
        let selected = i == state.active_tab;
        let style = if selected {
            Style::default()
                .fg(Color::Cyan)
                .add_modifier(Modifier::BOLD)
        } else {
            Style::default().fg(Color::White)
        };
        let prefix = if selected { "● " } else { "  " };
        lines.push(Line::from(Span::styled(format!("{}{}", prefix, tab.name), style)));
    }

    // Session entries from JSONL (recent Claude sessions)
    if !state.session_entries.is_empty() {
        lines.push(Line::default());
        lines.push(Line::from(Span::styled(
            "── Recent ──",
            Style::default().fg(Color::DarkGray),
        )));
        let max_title_width = inner.width.saturating_sub(4) as usize;
        let visible_count = (inner.height as usize).saturating_sub(lines.len() + 1) / 2 + 1;
        for entry in state.session_entries.iter().take(visible_count.max(5)) {
            let title = if entry.title.len() > max_title_width && max_title_width > 1 {
                format!("{}…", &entry.title[..max_title_width.saturating_sub(1)])
            } else {
                entry.title.clone()
            };
            lines.push(Line::from(Span::styled(
                format!("  {}", title),
                Style::default().fg(Color::Gray),
            )));
            lines.push(Line::default());
        }
    }

    let para = Paragraph::new(lines);
    f.render_widget(para, inner);
}
